import{_ as l,b as o,e as s,al as a}from"./chunks/framework.DrQIcdFj.js";(function(){try{var t=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};t.SENTRY_RELEASE={id:"abf23ae41d8e9798d1084c6d3fd2516340828177"};var e=new t.Error().stack;e&&(t._sentryDebugIds=t._sentryDebugIds||{},t._sentryDebugIds[e]="cfb5d423-0076-4973-a8b1-df2118d26c63",t._sentryDebugIdIdentifier="sentry-dbid-cfb5d423-0076-4973-a8b1-df2118d26c63")}catch{}})();const y=JSON.parse('{"title":"HTML 常用标签 (Common Tags)","description":"","frontmatter":{},"headers":[],"relativePath":"html/basic/commonTags.md","filePath":"html/basic/commonTags.md","lastUpdated":null}'),n={name:"html/basic/commonTags.md"};function i(t,e,d,r,g,c){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="html-常用标签-common-tags" tabindex="-1">HTML 常用标签 (Common Tags) <a class="header-anchor" href="#html-常用标签-common-tags" aria-label="Permalink to &quot;HTML 常用标签 (Common Tags)&quot;">​</a></h1><p>HTML 标签有上百个，但实际开发中 90% 的场景只用到其中约 20-30 个。本文将重点梳理这些高频核心标签。</p><h2 id="_1-结构与元数据-document-structure" tabindex="-1">1. 结构与元数据 (Document Structure) <a class="header-anchor" href="#_1-结构与元数据-document-structure" aria-label="Permalink to &quot;1. 结构与元数据 (Document Structure)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">标签</th><th style="text-align:left;">核心属性</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>&lt;!DOCTYPE html&gt;</code></strong></td><td style="text-align:left;">-</td><td style="text-align:left;"><strong>文档类型声明</strong>。必须在第一行。触发标准渲染模式。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;html&gt;</code></strong></td><td style="text-align:left;"><code>lang=&quot;zh-CN&quot;</code></td><td style="text-align:left;">根元素。<code>lang</code> 用于定义页面语言（影响翻译提示、读屏软件）。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;head&gt;</code></strong></td><td style="text-align:left;">-</td><td style="text-align:left;">存放元数据（CSS链接、标题、字符集），内容不显示在页面中。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;meta&gt;</code></strong></td><td style="text-align:left;"><code>charset=&quot;UTF-8&quot;</code><br><code>name=&quot;viewport&quot; content=&quot;...&quot;</code></td><td style="text-align:left;">定义字符集（防乱码）和视口设置（<strong>移动端适配必写</strong>）。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;title&gt;</code></strong></td><td style="text-align:left;">-</td><td style="text-align:left;">网页标题（显示在浏览器标签页和搜索结果中）。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;body&gt;</code></strong></td><td style="text-align:left;">-</td><td style="text-align:left;">网页可见内容的主体容器。</td></tr></tbody></table><h2 id="_2-文本与排版-text-typography" tabindex="-1">2. 文本与排版 (Text &amp; Typography) <a class="header-anchor" href="#_2-文本与排版-text-typography" aria-label="Permalink to &quot;2. 文本与排版 (Text &amp; Typography)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标签</th><th>描述</th><th>注意事项</th></tr></thead><tbody><tr><td><strong><code>&lt;h1&gt;~&lt;h6&gt;</code></strong></td><td>标题</td><td>h1 一个页面建议只用一次（Logo或主标题）。</td></tr><tr><td><strong><code>&lt;p&gt;</code></strong></td><td>段落</td><td>块级元素，默认有上下间距。不可包裹块级元素（如 div）。</td></tr><tr><td><strong><code>&lt;span&gt;</code></strong></td><td>行内容器</td><td>用于给一段话中的几个字单独加颜色/样式。</td></tr><tr><td><strong><code>&lt;a&gt;</code></strong></td><td>超链接</td><td><strong><code>target=&quot;_blank&quot;</code></strong> 打开新窗口时，建议加 <strong><code>rel=&quot;noopener&quot;</code></strong>.</td></tr><tr><td><strong><code>&lt;strong&gt;</code></strong></td><td>加粗 (强调)</td><td>比 <strong><code>&lt;b&gt;</code></strong> 语义更重，SEO 权重更高。</td></tr><tr><td><strong><code>&lt;em&gt;</code></strong></td><td>斜体 (语气)</td><td>比 <strong><code>&lt;i&gt;</code></strong> 语义更重。</td></tr><tr><td><strong><code>&lt;br&gt;</code></strong></td><td>换行</td><td>尽量少用，布局间距请用 CSS margin。</td></tr><tr><td><strong><code>&lt;hr&gt;</code></strong></td><td>分割线</td><td>语义上的主题转换。</td></tr></tbody></table><h2 id="_3-嵌入资源-embedded-content" tabindex="-1">3. 嵌入资源 (Embedded Content) <a class="header-anchor" href="#_3-嵌入资源-embedded-content" aria-label="Permalink to &quot;3. 嵌入资源 (Embedded Content)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">标签</th><th style="text-align:left;">核心属性</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>&lt;img&gt;</code></strong></td><td style="text-align:left;"><code>src</code>: 图片路径<br><code>alt</code>: 替代文本 (必填)<br><code>loading=&quot;lazy&quot;</code></td><td style="text-align:left;">图片。<code>alt</code> 用于图片挂掉时显示，以及 SEO。<code>lazy</code> 开启懒加载。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;video&gt;</code></strong></td><td style="text-align:left;"><code>src</code>, <code>controls</code> (显示控制条), <code>autoplay</code> (自动播放), <code>muted</code> (静音), <code>loop</code> (循环)</td><td style="text-align:left;">视频播放器。<strong>注意</strong>：现代浏览器禁止带声音的自动播放，必须配合 <code>muted</code> 才能 <code>autoplay</code>。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;audio&gt;</code></strong></td><td style="text-align:left;"><code>src</code>, <code>controls</code>, <code>loop</code></td><td style="text-align:left;">音频播放器。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;iframe&gt;</code></strong></td><td style="text-align:left;"><code>src</code>, <code>frameborder=&quot;0&quot;</code></td><td style="text-align:left;">内嵌框架。用于在网页里嵌入另一个网页（如 B站视频、地图）。</td></tr></tbody></table><h2 id="_4-容器与布局-containers" tabindex="-1">4. 容器与布局 (Containers) <a class="header-anchor" href="#_4-容器与布局-containers" aria-label="Permalink to &quot;4. 容器与布局 (Containers)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">标签</th><th style="text-align:left;">描述</th><th style="text-align:left;">场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>&lt;div&gt;</code></strong></td><td style="text-align:left;"><strong>通用容器</strong> (无语义)。</td><td style="text-align:left;">仅仅为了布局、加样式时使用。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;header&gt;</code></strong></td><td style="text-align:left;">页眉。</td><td style="text-align:left;">Logo、主导航、搜索栏区域。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;footer&gt;</code></strong></td><td style="text-align:left;">页脚。</td><td style="text-align:left;">版权声明、友情链接、联系方式。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;nav&gt;</code></strong></td><td style="text-align:left;">导航。</td><td style="text-align:left;">包裹主菜单链接列表 (<code>&lt;ul&gt;</code>)。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;main&gt;</code></strong></td><td style="text-align:left;">主体内容。</td><td style="text-align:left;"><strong>一个页面只能有一个</strong>，包裹核心内容。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;section&gt;</code></strong></td><td style="text-align:left;">章节/区块。</td><td style="text-align:left;">文档中的独立部分，通常带有标题 (<code>h2-h6</code>)。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;article&gt;</code></strong></td><td style="text-align:left;">独立文章。</td><td style="text-align:left;">博客文章、新闻卡片、帖子（可独立分发的内容）。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;aside&gt;</code></strong></td><td style="text-align:left;">侧边栏/相关内容。</td><td style="text-align:left;">广告、推荐阅读、目录。</td></tr></tbody></table><h2 id="_5-列表-lists" tabindex="-1">5. 列表 (Lists) <a class="header-anchor" href="#_5-列表-lists" aria-label="Permalink to &quot;5. 列表 (Lists)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">标签</th><th style="text-align:left;">子标签</th><th style="text-align:left;">描述</th><th style="text-align:left;">场景</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>&lt;ul&gt;</code></strong></td><td style="text-align:left;"><code>&lt;li&gt;</code></td><td style="text-align:left;"><strong>无序列表</strong> (Unordered)</td><td style="text-align:left;">导航栏、菜单、新闻列表。前面带圆点。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;ol&gt;</code></strong></td><td style="text-align:left;"><code>&lt;li&gt;</code></td><td style="text-align:left;"><strong>有序列表</strong> (Ordered)</td><td style="text-align:left;">排行榜、步骤说明。前面带数字 1,2,3。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;dl&gt;</code></strong></td><td style="text-align:left;"><code>&lt;dt&gt;</code>, <code>&lt;dd&gt;</code></td><td style="text-align:left;"><strong>定义列表</strong></td><td style="text-align:left;">术语解释、键值对（问题-答案）。</td></tr></tbody></table><h2 id="_6-表单-forms-——-用户交互核心" tabindex="-1">6. 表单 (Forms) —— 用户交互核心 <a class="header-anchor" href="#_6-表单-forms-——-用户交互核心" aria-label="Permalink to &quot;6. 表单 (Forms) —— 用户交互核心&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">标签</th><th style="text-align:left;">关键属性</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>&lt;form&gt;</code></strong></td><td style="text-align:left;"><code>action</code>, <code>method</code></td><td style="text-align:left;">表单域容器。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;input&gt;</code></strong></td><td style="text-align:left;"><code>type=&quot;...&quot;</code></td><td style="text-align:left;">万能输入框。<br><code>text</code> (文本), <code>password</code> (密码), <code>checkbox</code> (多选), <code>radio</code> (单选), <code>file</code> (上传), <code>submit</code> (提交)。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;textarea&gt;</code></strong></td><td style="text-align:left;"><code>rows</code>, <code>cols</code></td><td style="text-align:left;">多行文本域。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;button&gt;</code></strong></td><td style="text-align:left;"><code>type=&quot;button/submit&quot;</code></td><td style="text-align:left;">按钮。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;label&gt;</code></strong></td><td style="text-align:left;"><code>for=&quot;id&quot;</code></td><td style="text-align:left;">标签说明。<strong>点击 label 会自动聚焦到对应的 input</strong>（提升体验的关键）。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;select&gt;</code></strong></td><td style="text-align:left;"><code>&lt;option&gt;</code></td><td style="text-align:left;">下拉选择框。</td></tr></tbody></table><h2 id="_7-表格-tables" tabindex="-1">7. 表格 (Tables) <a class="header-anchor" href="#_7-表格-tables" aria-label="Permalink to &quot;7. 表格 (Tables)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">标签</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>&lt;table&gt;</code></strong></td><td style="text-align:left;">表格容器。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;thead&gt;</code></strong></td><td style="text-align:left;">表头区域。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;tbody&gt;</code></strong></td><td style="text-align:left;">表体区域。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;tr&gt;</code></strong></td><td style="text-align:left;">行 (Table Row)。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;th&gt;</code></strong></td><td style="text-align:left;">表头单元格 (Table Header)，默认加粗居中。</td></tr><tr><td style="text-align:left;"><strong><code>&lt;td&gt;</code></strong></td><td style="text-align:left;">普通单元格 (Table Data)。</td></tr></tbody></table><h2 id="_8-常见问题-faq-与-避坑指南" tabindex="-1">8. 常见问题 (FAQ) 与 避坑指南 <a class="header-anchor" href="#_8-常见问题-faq-与-避坑指南" aria-label="Permalink to &quot;8. 常见问题 (FAQ) 与 避坑指南&quot;">​</a></h2><h3 id="_8-1-div-和-span-到底有什么区别" tabindex="-1">8.1 <code>&lt;div&gt;</code> 和 <code>&lt;span&gt;</code> 到底有什么区别？ <a class="header-anchor" href="#_8-1-div-和-span-到底有什么区别" aria-label="Permalink to &quot;8.1 `&lt;div&gt;` 和 `&lt;span&gt;` 到底有什么区别？&quot;">​</a></h3><p>这是面试常考题，也是布局基础。</p><ul><li><strong><code>&lt;div&gt;</code> (Block 块级)</strong>: 独占一行，宽度默认撑满父容器，可以设置宽高、margin、padding。<strong>用于布局</strong>。</li><li><strong><code>&lt;span&gt;</code> (Inline 行内)</strong>: 不独占一行，宽度由内容撑开，<strong>不能</strong>设置宽高（设置了也无效），垂直方向的 margin 无效。<strong>用于修饰文字</strong>。</li></ul><h3 id="_8-2-src-和-href-有什么区别" tabindex="-1">8.2 <code>src</code> 和 <code>href</code> 有什么区别？ <a class="header-anchor" href="#_8-2-src-和-href-有什么区别" aria-label="Permalink to &quot;8.2 `src` 和 `href` 有什么区别？&quot;">​</a></h3><ul><li><strong><code>src</code> (Source)</strong>: <strong>引入资源</strong>。浏览器会下载并<strong>替换</strong>当前标签的内容（如 <code>img</code>, <code>script</code>, <code>video</code>）。解析到 src 时会暂停其他渲染，直到下载完成。</li><li><strong><code>href</code> (Hypertext Reference)</strong>: <strong>建立链接</strong>。浏览器会建立当前文档与目标资源的联系（如 <code>link</code> CSS, <code>a</code> 标签）。不会阻塞页面渲染。</li></ul><h3 id="_8-3-为什么我的图片下面有一条莫名其妙的空白缝隙" tabindex="-1">8.3 为什么我的图片下面有一条莫名其妙的空白缝隙？ <a class="header-anchor" href="#_8-3-为什么我的图片下面有一条莫名其妙的空白缝隙" aria-label="Permalink to &quot;8.3 为什么我的图片下面有一条莫名其妙的空白缝隙？&quot;">​</a></h3><p><strong>现象</strong>: <code>div</code> 包裹 <code>img</code>，图片底部会有约 3-5px 的空隙，导致 div 比图片高。</p><p><strong>原因</strong>: 图片默认是 <code>inline</code> 元素，遵循文字排版规则，底部留空是为了放字母（如 j, g, y）的下伸部分。</p><p><strong>解法</strong>: 把图片转为块级。 <code>img { display: block; }</code></p><h3 id="_8-4-button-和-input-type-button-选哪个" tabindex="-1">8.4 <code>&lt;button&gt;</code> 和 <code>&lt;input type=&quot;button&quot;&gt;</code> 选哪个？ <a class="header-anchor" href="#_8-4-button-和-input-type-button-选哪个" aria-label="Permalink to &quot;8.4 `&lt;button&gt;` 和 `&lt;input type=&quot;button&quot;&gt;` 选哪个？&quot;">​</a></h3><p><strong>推荐 <code>&lt;button&gt;</code></strong>。</p><ul><li><code>&lt;button&gt;提交&lt;/button&gt;</code>: 是双标签，中间可以放文字、图标甚至图片，样式更灵活，伪元素更好用。</li><li><code>&lt;input type=&quot;button&quot; value=&quot;提交&quot;&gt;</code>: 是单标签，只能通过 <code>value</code> 属性设置纯文字，样式受限。</li></ul><h3 id="_8-5-为什么表单里的-radio-单选框可以多选" tabindex="-1">8.5 为什么表单里的 <code>radio</code> 单选框可以多选？ <a class="header-anchor" href="#_8-5-为什么表单里的-radio-单选框可以多选" aria-label="Permalink to &quot;8.5 为什么表单里的 `radio` 单选框可以多选？&quot;">​</a></h3><p><strong>原因</strong>: 没有给它们设置相同的 <code>name</code> 属性。</p><p><strong>解法</strong>:</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- name 必须一样，才是一组 --&gt;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;radio&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gender&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;male&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt; 男</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">input</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;radio&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;gender&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;female&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt; 女</span></span></code></pre></div><h3 id="_8-6-target-blank-有安全隐患" tabindex="-1">8.6 <code>target=&quot;_blank&quot;</code> 有安全隐患？ <a class="header-anchor" href="#_8-6-target-blank-有安全隐患" aria-label="Permalink to &quot;8.6 `target=&quot;_blank&quot;` 有安全隐患？&quot;">​</a></h3><p>是的。当你在新窗口打开外链时，新页面可以通过 <code>window.opener</code> 控制原页面（例如跳转到钓鱼网站）。</p><p><strong>解法</strong>: 总是搭配 <code>rel</code> 属性使用。rel=&quot;noopener noreferrer&quot;在安全范围内</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;...&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> target</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;_blank&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> rel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;noopener noreferrer&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;外部链接&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div>',37)])])}const p=l(n,[["render",i]]);export{y as __pageData,p as default};
